// Some portions generated by Codex
package org.eclipse.rdf4j.sail.lmdb;

import static org.assertj.core.api.Assertions.assertThat;

import java.lang.reflect.Method;
import java.util.ArrayList;
import java.util.HashMap;
import java.util.List;
import java.util.Map;

import org.eclipse.rdf4j.common.iteration.CloseableIteration;
import org.eclipse.rdf4j.query.BindingSet;
import org.eclipse.rdf4j.query.algebra.evaluation.QueryBindingSet;
import org.eclipse.rdf4j.query.algebra.evaluation.QueryEvaluationStep;
import org.eclipse.rdf4j.query.impl.EmptyBindingSet;
import org.junit.jupiter.api.Test;

class LmdbLftjCodegenTest {

	@Test
	void planShouldExposeStableExecutionKeyAcrossCopies() {
		LmdbLftjPlan plan = LmdbLftjSyntheticScenario.createPlan();

		assertThat(invokeStringGetter(plan, "executionKey"))
				.isEqualTo(invokeStringGetter(plan.copy(), "executionKey"));
	}

	@Test
	void syntheticQueryAccessShouldEnableCodegenByDefault() {
		assertThat(invokeBooleanGetter(new LmdbLftjSyntheticScenario.TestQueryAccess(), "lftjCodegenEnabled"))
				.isTrue();
	}

	@Test
	void compiledAndInterpretedShouldProduceSameRowsForSyntheticCycle() {
		LmdbLftjPlan plan = LmdbLftjSyntheticScenario.createPlan();

		List<String> interpreted = drain(
				LmdbLftjSyntheticScenario.createEvaluationStep(new InterpretedQueryAccess(), plan),
				EmptyBindingSet.getInstance());
		List<String> compiled = drain(
				LmdbLftjSyntheticScenario.createEvaluationStep(new CachingQueryAccess(new CountingCompiler()), plan),
				EmptyBindingSet.getInstance());

		assertThat(compiled).isNotEmpty().containsExactlyElementsOf(interpreted);
	}

	@Test
	void compiledAndInterpretedShouldMatchForHiddenContextMultiplicity() {
		LmdbLftjPlan plan = LmdbLftjSyntheticScenario.createPlanWithHiddenContexts();

		List<String> interpreted = drain(
				LmdbLftjSyntheticScenario.createEvaluationStep(new InterpretedQueryAccess(true), plan),
				EmptyBindingSet.getInstance());
		List<String> compiled = drain(
				LmdbLftjSyntheticScenario.createEvaluationStep(
						new CachingQueryAccess(true, new CountingCompiler()), plan),
				EmptyBindingSet.getInstance());

		assertThat(compiled).hasSize(648).containsExactlyElementsOf(interpreted);
	}

	@Test
	void compiledAndInterpretedShouldMatchForFullyBoundInput() {
		LmdbLftjPlan plan = LmdbLftjSyntheticScenario.createPlan();
		QueryBindingSet matchingBindings = new QueryBindingSet();
		matchingBindings.setBinding("a", LmdbLftjSyntheticScenario.VF.createIRI("urn:person:1"));
		matchingBindings.setBinding("b", LmdbLftjSyntheticScenario.VF.createIRI("urn:person:2"));
		matchingBindings.setBinding("c", LmdbLftjSyntheticScenario.VF.createIRI("urn:person:3"));

		List<String> interpreted = drain(
				LmdbLftjSyntheticScenario.createEvaluationStep(new InterpretedQueryAccess(), plan), matchingBindings);
		List<String> compiled = drain(
				LmdbLftjSyntheticScenario.createEvaluationStep(new CachingQueryAccess(new CountingCompiler()), plan),
				matchingBindings);

		assertThat(compiled).containsExactlyElementsOf(interpreted);
	}

	@Test
	void codegenCacheShouldCompileOncePerExecutionKey() {
		LmdbLftjPlan plan = LmdbLftjSyntheticScenario.createPlan();
		CountingCompiler compiler = new CountingCompiler();
		CachingQueryAccess queryAccess = new CachingQueryAccess(compiler);
		QueryEvaluationStep evaluationStep = LmdbLftjSyntheticScenario.createEvaluationStep(queryAccess, plan);

		List<String> first = drain(evaluationStep, EmptyBindingSet.getInstance());
		List<String> second = drain(evaluationStep, EmptyBindingSet.getInstance());

		assertThat(second).containsExactlyElementsOf(first);
		assertThat(compiler.compileCalls).isEqualTo(1);
		assertThat(queryAccess.cachedEntry(plan.executionKey())).isNotNull();
		assertThat(queryAccess.cachedEntry(plan.executionKey()).compiled())
				.as(compiler.failureDescription())
				.isTrue();
	}

	@Test
	void codegenCacheShouldReuseNegativeResultAfterCompileFailure() {
		LmdbLftjPlan plan = LmdbLftjSyntheticScenario.createPlan();
		FailingCompiler compiler = new FailingCompiler();
		CachingQueryAccess queryAccess = new CachingQueryAccess(compiler);
		QueryEvaluationStep evaluationStep = LmdbLftjSyntheticScenario.createEvaluationStep(queryAccess, plan);

		List<String> first = drain(evaluationStep, EmptyBindingSet.getInstance());
		List<String> second = drain(evaluationStep, EmptyBindingSet.getInstance());

		assertThat(second).containsExactlyElementsOf(first);
		assertThat(compiler.compileCalls).isEqualTo(1);
		assertThat(queryAccess.cachedEntry(plan.executionKey())).isNotNull();
		assertThat(queryAccess.cachedEntry(plan.executionKey()).compiled()).isFalse();
		assertThat(queryAccess.cachedEntry(plan.executionKey()).failureMessage()).contains("forced failure");
	}

	private boolean invokeBooleanGetter(Object target, String getterName) {
		try {
			Method getter = target.getClass().getMethod(getterName);
			return (boolean) getter.invoke(target);
		} catch (ReflectiveOperationException e) {
			throw new AssertionError("Missing LMDB codegen boolean getter: " + getterName, e);
		}
	}

	private String invokeStringGetter(Object target, String getterName) {
		try {
			Method getter = target.getClass().getMethod(getterName);
			return (String) getter.invoke(target);
		} catch (ReflectiveOperationException e) {
			throw new AssertionError("Missing LMDB codegen string getter: " + getterName, e);
		}
	}

	private List<String> drain(QueryEvaluationStep evaluationStep, BindingSet bindings) {
		List<String> rows = new ArrayList<>();
		try (CloseableIteration<BindingSet> iteration = evaluationStep.evaluate(bindings)) {
			while (iteration.hasNext()) {
				BindingSet row = iteration.next();
				rows.add(render(row));
			}
		}
		return rows;
	}

	private String render(BindingSet row) {
		return row.getValue("a").stringValue() + "|" + row.getValue("b").stringValue() + "|"
				+ row.getValue("c").stringValue();
	}

	private static final class InterpretedQueryAccess extends LmdbLftjSyntheticScenario.TestQueryAccess {

		private InterpretedQueryAccess() {
			super();
		}

		private InterpretedQueryAccess(boolean duplicateContexts) {
			super(duplicateContexts);
		}

		@Override
		public boolean lftjCodegenEnabled() {
			return false;
		}
	}

	private static final class CachingQueryAccess extends LmdbLftjSyntheticScenario.TestQueryAccess {
		private final Map<String, LmdbLftjCodegenCache.CacheEntry> compiledPlans = new HashMap<>();
		private final LmdbLftjCodegenCompiler compiler;

		private CachingQueryAccess(LmdbLftjCodegenCompiler compiler) {
			this(false, compiler);
		}

		private CachingQueryAccess(boolean duplicateContexts, LmdbLftjCodegenCompiler compiler) {
			super(duplicateContexts);
			this.compiler = compiler;
		}

		@Override
		public LmdbLftjCodegenCache.CacheEntry cachedCompiledPlan(String executionKey) {
			return compiledPlans.get(executionKey);
		}

		@Override
		public void cacheCompiledPlanSuccess(String executionKey, LmdbCompiledLftjFactory factory) {
			compiledPlans.put(executionKey, LmdbLftjCodegenCache.CacheEntry.success(factory));
		}

		@Override
		public void cacheCompiledPlanFailure(String executionKey, String message) {
			compiledPlans.put(executionKey, LmdbLftjCodegenCache.CacheEntry.failure(message));
		}

		@Override
		public LmdbLftjCodegenCompiler codegenCompiler() {
			return compiler;
		}

		private LmdbLftjCodegenCache.CacheEntry cachedEntry(String executionKey) {
			return compiledPlans.get(executionKey);
		}
	}

	private static class CountingCompiler extends LmdbLftjCodegenCompiler {
		private int compileCalls;
		private RuntimeException failure;

		@Override
		LmdbCompiledLftjFactory compile(LmdbLftjPlan plan, LmdbLftjExecutionShape shape) {
			compileCalls++;
			try {
				return super.compile(plan, shape);
			} catch (RuntimeException e) {
				failure = e;
				throw e;
			}
		}

		private String failureDescription() {
			if (failure == null) {
				return "expected compiled factory cache entry";
			}
			Throwable cause = failure.getCause();
			return cause == null ? failure.toString() : failure + " | cause=" + cause;
		}
	}

	private static final class FailingCompiler extends LmdbLftjCodegenCompiler {
		private int compileCalls;

		@Override
		LmdbCompiledLftjFactory compile(LmdbLftjPlan plan, LmdbLftjExecutionShape shape) {
			compileCalls++;
			throw new IllegalArgumentException("forced failure");
		}
	}
}
